$ser_content = 'a:2:{s:7:"CONTENT";s:5421:"<div class="blog-text__content">
            <div class="tags blog-text__tags">
                            <a
                        class="tag blog-text__tag"
                        href="/blog/?tags=%D0%B6%D0%B5%D0%BD%D1%89%D0%B8%D0%BD%D0%B0%D0%BC"
